// Read directly from Firestore document
const job_id = $json.job_id;

// If this node is triggered after a webhook, keep fallback
const reason =
  $json.reason ||
  $json.body?.reason ||
  "Rejected by operator";

if (!job_id) {
  throw new Error("Missing job_id in Firestore document");
}

if ($json.status !== "AWAITING_APPROVAL") {
  throw new Error("Rejection allowed only when status is AWAITING_APPROVAL");
}

return [
  {
    json: {
      job_id,
      status: "rejected",   // correct state transition
      rejected_at: new Date().toISOString(),
      rejected_by: "operator",
      failure_reason: reason
    }
  }
];

// Firestore returns document fields directly in $json
const job_id = $json.job_id;

if (!job_id) {
  throw new Error("Missing job_id in Firestore document");
}

if ($json.status !== "AWAITING_APPROVAL") {
  throw new Error("Approval allowed only when status is AWAITING_APPROVAL");
}

return [
  {
    json: {
      job_id,
      status: "approved",
      approved_at: new Date().toISOString(),
      approved_by: "operator"
    }
  }
];

// Canonical job from Firestore (this node input)
const job = $json;

// Incoming attempt from webhook
const body = $node["Fork Simulate"].json.body || {};

const incoming_job_id = body.job_id;
const incoming_identity_id = body.identity_id;
const attempted_by = body.attempted_by || "unknown";
const reason = body.reason || "duplicate instantiation test";

if (!incoming_job_id) throw new Error("Missing job_id in fork-simulate payload");
if (!incoming_identity_id) throw new Error("Missing identity_id in fork-simulate payload");

if (!job || !job.job_id) throw new Error("Canonical job not found in Firestore");
if (!job.identity_id) throw new Error("Canonical job missing identity_id (did you update Initialize Job + Firestore columns?)");

// Terminal statuses (fork attempts allowed only if canonical job is already terminal)
const TERMINAL = ["completed", "rejected", "failed"];
const isTerminal = TERMINAL.includes(String(job.status || "").toLowerCase());

// Fork detection
const identityMatches = String(incoming_identity_id) === String(job.identity_id);

let fork_detected = false;
let fork_status = "allowed";
let block_reason = "";

if (identityMatches && !isTerminal) {
  fork_detected = true;
  fork_status = "fork_quarantined"; // or "blocked"
  block_reason = `Duplicate identity detected. Canonical job ${job.job_id} is still active (status=${job.status}).`;
}

// Create a safe event id
const ts = new Date().toISOString().replace(/[:.]/g, "-");
const fork_event_id = `fork-${ts}-${job.job_id}`;

// ✅ Fields your Firestore fork_events collection should store
const action_taken = fork_detected ? "quarantined" : "allowed";

return [{
  json: {
    // ---- fork_events schema (so Firestore can write without per-field mapping)
    event_id: fork_event_id,
    job_id: job.job_id,
    identity_id: job.identity_id,
    attempted_by,
    reason,
    created_at: new Date().toISOString(),
    block_reason,
    action_taken,

    // ---- keep extra debug info (optional, safe)
    fork_detected,
    fork_status,

    canonical_job_id: job.job_id,
    canonical_status: job.status,
    canonical_identity_id: job.identity_id,

    incoming_job_id,
    incoming_identity_id
  }
}];

const crypto = require("crypto");
const b = $json.body || {};

const s = (v) => (v === null || v === undefined ? "" : String(v).trim());
const hex = (v) => {
  if (v === null || v === undefined || v === "") return null;

  const raw = String(v).trim()
    .replace(/^hex:/i, "")
    .replace(/^0x/i, "");

  return `hex:0x${raw}`;
};

const sha256 = (value) =>
  crypto.createHash("sha256").update(String(value)).digest("hex");

if (!s(b.agent_id)) throw new Error("missing_agent_id");
if (!s(b.owner_org_id)) throw new Error("missing_owner_org_id");
if (!s(b.governance_profile)) throw new Error("missing_governance_profile");
if (!s(b.jurisdiction)) throw new Error("missing_jurisdiction");
if (!s(b.mission)) throw new Error("missing_mission");

// immutable identity ingredients
const mission = s(b.mission);
const policy = s(b.policy || "NXQ_DEFAULT_POLICY");
const identity_version = s(b.identity_version || "v1");
const public_key = s(
  b.public_key ||
  b.card_public_key ||
  b.acelogic_card?.public_key ||
  ""
);

const mission_hash = hex(sha256(mission));
const policy_hash = hex(sha256(policy));

// canonical identity object: ONLY immutable fields
const canonical_identity_json = {
  agent_id: s(b.agent_id),
  governance_profile: s(b.governance_profile),
  identity_version,
  jurisdiction: s(b.jurisdiction),
  mission_hash,
  owner_org_id: s(b.owner_org_id),
  policy_hash,
  public_key
};

// sorted-key canonical string
const canonical_identity_json_string = JSON.stringify(
  Object.keys(canonical_identity_json)
    .sort()
    .reduce((acc, key) => {
      acc[key] = canonical_identity_json[key];
      return acc;
    }, {})
);

const identity_fingerprint = hex(sha256(canonical_identity_json_string));

return [{
  json: {
    agent_id: s(b.agent_id),
    display_name: s(b.display_name),
    agent_class: s(b.agent_class),
    owner_org_id: s(b.owner_org_id),
    acelogic_id: s(b.acelogic_id),

    identity_fingerprint,
    canonical_identity_json,
    mission_hash,
    policy_hash,
    identity_version,
    public_key,

    jurisdiction: s(b.jurisdiction),
    governance_profile: s(b.governance_profile),
    mission,

    continuity_status: s(b.continuity?.status ?? "ACTIVE"),
    continuity_current_instance_id: b.continuity?.current_instance_id ?? null,
    continuity_lease_expires_at: b.continuity?.lease_expires_at ?? null,
    continuity_last_seen_at: b.continuity?.last_seen_at ?? null,
    continuity_resurrection_count: Number(b.continuity?.resurrection_count ?? 0),
    continuity_fork_flag: Boolean(b.continuity?.fork_flag ?? false),

    covenant_hash: hex(
      b.anchors?.covenant_hash ??
      identity_fingerprint
    ),
    cvr_polygon: b.anchors?.cvr_polygon ? hex(b.anchors.cvr_polygon) : null,
    cvr_xrpl: b.anchors?.cvr_xrpl ? hex(b.anchors.cvr_xrpl) : null,

    created_at: s(b.created_at ?? new Date().toISOString())
  }
}];

return [{
  json: {
    ok: false,
    error: "LEASE_HELD_OR_FORK_RISK",
    reason: $json.reason || "lease_denied",
    current_instance_id: $json.current_instance_id || null,
    requested_instance_id: $json.instance_id || null
  }
}];

const input = items[0].json;
const now = new Date().toISOString();

if (!input.agent_id) {
  throw new Error("missing_agent_id");
}

if (!input.identity_fingerprint) {
  throw new Error("missing_identity_fingerprint");
}

const instance_id =
  input.instance_id ||
  `inst_${input.agent_id}_${Date.now()}`;

const payload = {
  ...input,
  instance_id,
  status: input.status || "RUNNING",
  started_at: input.started_at || now,
  last_seen_at: now,
  ended_at: input.ended_at || null,
  host_build_id: input.host_build_id || "nxq-node-01",
  runtime_version: input.runtime_version || "nxq-runtime-v1",
  instance_payload: {
    instance_id,
    agent_id: input.agent_id,
    identity_fingerprint: input.identity_fingerprint,
    status: input.status || "RUNNING",
    started_at: input.started_at || now,
    last_seen_at: now,
    ended_at: input.ended_at || null,
    host_build_id: input.host_build_id || "nxq-node-01",
    runtime_version: input.runtime_version || "nxq-runtime-v1"
  }
};

return [{ json: payload }];

const input = items[0].json;
const body = input.body ?? input;

const requested_agent_id =
  typeof body.requested_agent_id === "string"
    ? body.requested_agent_id.trim()
    : "";

const user_id =
  typeof body.user_id === "string"
    ? body.user_id.trim()
    : "";

const job_type =
  typeof body.job_type === "string"
    ? body.job_type.trim().toLowerCase()
    : "";

const prompt =
  typeof body.prompt === "string"
    ? body.prompt.trim()
    : "";

if (!requested_agent_id) {
  throw new Error("missing_requested_agent_id");
}

if (!user_id) {
  throw new Error("missing_user_id");
}

if (!job_type) {
  throw new Error("missing_job_type");
}

if (!prompt) {
  throw new Error("missing_prompt");
}

return [
  {
    json: {
      requested_agent_id,
      user_id,
      job_type,
      prompt
    }
  }
];

const data = items[0].json;

const requested_agent_id =
  typeof data.requested_agent_id === "string"
    ? data.requested_agent_id.trim()
    : "";

if (!requested_agent_id) {
  throw new Error("missing_requested_agent_id");
}

return [
  {
    json: {
      ...data,
      agent_id: requested_agent_id
    }
  }
];

const data = items[0].json;

// determine instance_id
const instance_id =
  data.instance_id ??
  data.continuity_current_instance_id ??
  null;

if (!instance_id) {
  throw new Error("missing_instance_id");
}

return [
  {
    json: {
      user_id: data.user_id,
      job_type: data.job_type,
      prompt: data.prompt,

      agent_id: data.agent_id,
      instance_id: instance_id,
      identity_fingerprint: data.identity_fingerprint ?? null,

      continuity_lease_expires_at: data.continuity_lease_expires_at ?? null,
      continuity_last_seen_at: data.continuity_last_seen_at ?? null
    }
  }
];

const data = items[0].json;

const nowMs = Date.now();

const instance_id = data.instance_id ?? null;
const current_instance_id = data.continuity_current_instance_id ?? null;
const lease_expires_at = data.continuity_lease_expires_at ?? null;

if (!instance_id) {
  throw new Error("missing_instance_id");
}

let lease_ok = false;
let lease_reason = "unknown";

if (!current_instance_id || !lease_expires_at) {
  lease_ok = true;
  lease_reason = "no_active_lease";
} else {
  const expiryMs = new Date(lease_expires_at).getTime();

  if (Number.isNaN(expiryMs)) {
    throw new Error("invalid_continuity_lease_expires_at");
  }

  if (expiryMs < nowMs) {
    lease_ok = true;
    lease_reason = "lease_expired";
  } else if (current_instance_id === instance_id) {
    lease_ok = true;
    lease_reason = "same_instance";
  } else {
    lease_ok = false;
    lease_reason = "lease_held_by_other_instance";
  }
}

return [
  {
    json: {
      ...data,
      lease_ok,
      lease_reason,
      new_lease_expires_at: new Date(nowMs + 60 * 1000).toISOString()
    }
  }
];

const data = items[0].json;

if (!data.agent_id) {
  throw new Error("missing_agent_id");
}

if (!data.instance_id) {
  throw new Error("missing_instance_id");
}

if (!data.new_lease_expires_at) {
  throw new Error("missing_new_lease_expires_at");
}

return [
  {
    json: {
      agent_id: data.agent_id,
      continuity_current_instance_id: data.instance_id,
      continuity_lease_expires_at: data.new_lease_expires_at,
      continuity_last_seen_at: new Date().toISOString(),
      continuity_status: "ACTIVE"
    }
  }
];

const data = items[0].json;

const now = new Date().toISOString();
const job_id = `job_${Date.now()}`;

if (!data.user_id) throw new Error("missing_user_id");
if (!data.job_type) throw new Error("missing_job_type");
if (!data.prompt) throw new Error("missing_prompt");
if (!data.agent_id) throw new Error("missing_agent_id");
if (!data.instance_id) throw new Error("missing_instance_id");
if (!data.identity_fingerprint) throw new Error("missing_identity_fingerprint");

return [
  {
    json: {
      job_id,
      user_id: data.user_id,
      job_type: data.job_type,
      prompt: data.prompt,

      requested_agent_id: data.agent_id,
      requested_identity_fingerprint: data.identity_fingerprint,
      assigned_agent_id: data.agent_id,
      assigned_instance_id: data.instance_id,
      identity_fingerprint: data.identity_fingerprint,

      status: "queued",
      retry_count: 0,

      created_at: now,
      updated_at: now,
      assigned_at: now
    }
  }
];

const data = items[0].json;

const now = new Date().toISOString();
const trace_id = `trace_${Date.now()}`;

if (!data.job_id) throw new Error("missing_job_id");
if (!data.assigned_agent_id) throw new Error("missing_assigned_agent_id");
if (!data.assigned_instance_id) throw new Error("missing_assigned_instance_id");
if (!data.identity_fingerprint) throw new Error("missing_identity_fingerprint");

return [
  {
    json: {
      trace_id,
      job_id: data.job_id,
      agent_id: data.assigned_agent_id,
      instance_id: data.assigned_instance_id,
      identity_fingerprint: data.identity_fingerprint,
      event_type: "JOB_ACCEPTED",
      event_status: data.status,
      timestamp: now
    }
  }
];

const input = $json;
const body = input.body ?? {};

// validate webhook body shape
if (typeof body !== 'object' || body === null || Array.isArray(body)) {
  throw new Error('INVALID_ROUTER_INPUT: request body must be a JSON object');
}

// allow only job_id inside body
const allowedBodyKeys = ['job_id'];
const receivedBodyKeys = Object.keys(body);

const unexpectedKeys = receivedBodyKeys.filter(
  (key) => !allowedBodyKeys.includes(key)
);

if (unexpectedKeys.length > 0) {
  throw new Error(
    `INVALID_ROUTER_INPUT: unexpected field(s) in body: ${unexpectedKeys.join(', ')}`
  );
}

// required field
if (typeof body.job_id !== 'string') {
  throw new Error('INVALID_ROUTER_INPUT: job_id is required and must be a string');
}

const jobId = body.job_id.trim();

if (!jobId) {
  throw new Error('INVALID_ROUTER_INPUT: job_id must not be empty');
}

if (jobId.length < 8 || jobId.length > 128) {
  throw new Error('INVALID_ROUTER_INPUT: job_id length is invalid');
}

if (!/^[A-Za-z0-9._:-]+$/.test(jobId)) {
  throw new Error('INVALID_ROUTER_INPUT: job_id contains invalid characters');
}

// explicit rejection of forbidden body fields
const forbiddenFields = [
  'assigned_agent_id',
  'assigned_instance_id',
  'identity_fingerprint',
  'authority_lease',
  'lease_expires_at',
  'agent_id',
  'instance_id',
  'acelogic_id',
  'identity_context',
  'runtime_context',
  'job_type',
  'provider',
  'model'
];

for (const field of forbiddenFields) {
  if (Object.prototype.hasOwnProperty.call(body, field)) {
    throw new Error(`INVALID_ROUTER_INPUT: forbidden field supplied in body: ${field}`);
  }
}

return [
  {
    json: {
      job_id: jobId
    }
  }
];

const job = $json;

// ensure job exists
if (!job || Object.keys(job).length === 0) {
  throw new Error('JOB_NOT_FOUND: jobs/{job_id} document does not exist');
}

// required fields
const requiredFields = [
  'assigned_agent_id',
  'assigned_instance_id',
  'identity_fingerprint',
  'job_type',
  'status'
];

for (const field of requiredFields) {
  if (!job[field]) {
    throw new Error(`INVALID_JOB_RECORD: missing required field ${field}`);
  }
}

// enforce correct lifecycle state
if (job.status !== 'queued') {
  throw new Error(`INVALID_JOB_STATE: expected queued but got ${job.status}`);
}

// normalize execution context
return [
  {
    json: {
      job_id: job.job_id,
      assigned_agent_id: job.assigned_agent_id,
      assigned_instance_id: job.assigned_instance_id,
      identity_fingerprint: job.identity_fingerprint,
      job_type: job.job_type,
      status: job.status,
      prompt: job.prompt,
      runtime_context: job.runtime_context || {}
    }
  }
];

const data = $json;

// required job fields from merged context
if (!data.job_id) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing job_id');
}
if (!data.assigned_agent_id) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing assigned_agent_id');
}
if (!data.assigned_instance_id) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing assigned_instance_id');
}
if (!data.identity_fingerprint) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing identity_fingerprint');
}
if (!data.job_type) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing job_type');
}

// required instance fields from Firestore
if (!data.instance_id) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing instance_id in agent_instances record');
}
if (!data.agent_id) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing agent_id in agent_instances record');
}
if (!data.status) {
  throw new Error('INSTANCE_VALIDATION_FAILED: missing status in agent_instances record');
}

// exact identity continuity checks
if (data.assigned_instance_id !== data.instance_id) {
  throw new Error(
    `INSTANCE_VALIDATION_FAILED: assigned_instance_id mismatch; expected ${data.assigned_instance_id} got ${data.instance_id}`
  );
}

if (data.assigned_agent_id !== data.agent_id) {
  throw new Error(
    `INSTANCE_VALIDATION_FAILED: assigned_agent_id mismatch; expected ${data.assigned_agent_id} got ${data.agent_id}`
  );
}

if (data.identity_fingerprint !== data.instance_identity_fingerprint) {
  throw new Error(
    `INSTANCE_VALIDATION_FAILED: identity_fingerprint mismatch; expected ${data.identity_fingerprint} got ${data.instance_identity_fingerprint}`
  );
}

if (data.status !== 'RUNNING') {
  throw new Error(
    `INSTANCE_VALIDATION_FAILED: instance status must be RUNNING, got ${data.status}`
  );
}

return [
  {
    json: {
      job_id: data.job_id,
      assigned_agent_id: data.assigned_agent_id,
      assigned_instance_id: data.assigned_instance_id,
      identity_fingerprint: data.identity_fingerprint,
      job_type: data.job_type,
      prompt: data.prompt,
      runtime_context: data.runtime_context || {},
      job_status: 'in_progress',
      status: 'in_progress',
      instance_status: data.status,
      instance_valid: true
    }
  }
];

return [
  {
    json: {
      ...$json,
      runtime_context: {
        ...($json.runtime_context || {}),
        active_stage: 'coo_planning',
        orchestration_mode: 'coo_worker_research',
        model_states: {
          ...(($json.runtime_context || {}).model_states || {}),
          coo: { status: 'in_progress' },
          research: { status: 'pending' },
          worker: { status: 'pending' }
        },
        token_usage: {
          ...(($json.runtime_context || {}).token_usage || {}),
          coo: {
            input_tokens: 0,
            output_tokens: 0
          },
          research: {
            input_tokens: 0,
            output_tokens: 0
          },
          worker: {
            input_tokens: 0,
            output_tokens: 0
          },
          total_input_tokens: 0,
          total_output_tokens: 0,
          total_tokens: 0
        }
      }
    }
  }
];

const data = $json;

const plan =
  data?.output?.[0]?.content?.[0]?.text;

if (!plan || typeof plan !== 'object' || Array.isArray(plan)) {
  throw new Error('COO_PLAN_NORMALIZATION_FAILED: missing plan object at output[0].content[0].text');
}

if (typeof plan.plan_summary !== 'string' || !plan.plan_summary.trim()) {
  throw new Error('COO_PLAN_NORMALIZATION_FAILED: missing plan_summary');
}

if (!Array.isArray(plan.steps) || plan.steps.length === 0) {
  throw new Error('COO_PLAN_NORMALIZATION_FAILED: steps must be a non-empty array');
}

for (const step of plan.steps) {
  if (!step || typeof step !== 'object') {
    throw new Error('COO_PLAN_NORMALIZATION_FAILED: invalid step entry');
  }
  if (typeof step.step_id !== 'string' || !step.step_id.trim()) {
    throw new Error('COO_PLAN_NORMALIZATION_FAILED: each step must include step_id');
  }
  if (!['research', 'worker'].includes(step.agent)) {
    throw new Error(`COO_PLAN_NORMALIZATION_FAILED: invalid agent ${step.agent}`);
  }
  if (typeof step.task !== 'string' || !step.task.trim()) {
    throw new Error(`COO_PLAN_NORMALIZATION_FAILED: step ${step.step_id} missing task`);
  }
}

const usage = data.usage || {};

return [
  {
    json: {
      job_id: data.job_id,
      assigned_agent_id: data.assigned_agent_id,
      assigned_instance_id: data.assigned_instance_id,
      identity_fingerprint: data.identity_fingerprint,
      job_type: data.job_type,
      prompt: data.prompt,
      runtime_context: data.runtime_context || {},
      plan: {
        plan_summary: plan.plan_summary,
        steps: plan.steps
      },
      coo_token_usage: {
        input_tokens: Number(usage.input_tokens || 0),
        output_tokens: Number(usage.output_tokens || 0),
        total_tokens: Number(usage.total_tokens || 0)
      }
    }
  }
];

const data = $json;

if (!data.job_id) {
  throw new Error('PREPARE_COO_PLAN_STATE_FAILED: missing job_id');
}

if (!data.plan || typeof data.plan !== 'object' || Array.isArray(data.plan)) {
  throw new Error('PREPARE_COO_PLAN_STATE_FAILED: missing plan');
}

if (!data.coo_token_usage || typeof data.coo_token_usage !== 'object') {
  throw new Error('PREPARE_COO_PLAN_STATE_FAILED: missing coo_token_usage');
}

const existingRuntimeContext = data.runtime_context || {};
const existingModelStates = existingRuntimeContext.model_states || {};
const existingTokenUsage = existingRuntimeContext.token_usage || {};

const cooInputTokens = Number(data.coo_token_usage.input_tokens || 0);
const cooOutputTokens = Number(data.coo_token_usage.output_tokens || 0);
const cooTotalTokens = Number(data.coo_token_usage.total_tokens || 0);

// preserve existing research/worker counters if already present
const researchInputTokens = Number(existingTokenUsage?.research?.input_tokens || 0);
const researchOutputTokens = Number(existingTokenUsage?.research?.output_tokens || 0);
const workerInputTokens = Number(existingTokenUsage?.worker?.input_tokens || 0);
const workerOutputTokens = Number(existingTokenUsage?.worker?.output_tokens || 0);

const totalInputTokens = cooInputTokens + researchInputTokens + workerInputTokens;
const totalOutputTokens = cooOutputTokens + researchOutputTokens + workerOutputTokens;
const totalTokens = cooTotalTokens + researchInputTokens + researchOutputTokens + workerInputTokens + workerOutputTokens;

return [
  {
    json: {
      ...data,
      runtime_context: {
        ...existingRuntimeContext,
        active_stage: 'plan_ready',
        plan: data.plan,
        model_states: {
          ...existingModelStates,
          coo: {
            ...(existingModelStates.coo || {}),
            status: 'completed'
          },
          research: {
            ...(existingModelStates.research || {}),
            status: 'ready'
          },
          worker: {
            ...(existingModelStates.worker || {}),
            status: 'ready'
          }
        },
        token_usage: {
          ...existingTokenUsage,
          coo: {
            ...(existingTokenUsage.coo || {}),
            input_tokens: cooInputTokens,
            output_tokens: cooOutputTokens
          },
          research: {
            ...(existingTokenUsage.research || {}),
            input_tokens: researchInputTokens,
            output_tokens: researchOutputTokens
          },
          worker: {
            ...(existingTokenUsage.worker || {}),
            input_tokens: workerInputTokens,
            output_tokens: workerOutputTokens
